import { RefractiveCursorLens } from "@/components/ui/refractive-cursor-lens";

export default function Article() {
  return (
    <RefractiveCursorLens className="max-w-3xl mx-auto py-16">
      <h1 className="text-5xl font-semibold tracking-tight">Field guide</h1>
      <p className="mt-6 text-lg text-neutral-700">
        Hover anywhere over this paragraph. The lens refracts the type beneath
        it without ever stealing the click — your selection, copy, and link
        navigation all keep working as if the lens weren&apos;t there.
      </p>
    </RefractiveCursorLens>
  );
}

"use client";
import { useRef } from "react";
import { RefractiveCursorLens } from "@/components/ui/refractive-cursor-lens";

export default function PhotoInspector() {
  const imgRef = useRef<HTMLImageElement>(null);
  return (
    <RefractiveCursorLens
      showOnlyOver={imgRef}
      size={160}
      displacementScale={28}
    >
      <div className="relative">
        <img
          ref={imgRef}
          src="https://images.unsplash.com/photo-1500964757637-c85e8a162699?auto=format&fit=crop&w=1600&q=80"
          alt=""
          className="w-full rounded-2xl"
        />
      </div>
    </RefractiveCursorLens>
  );
}

import { RefractiveCursorLens } from "@/components/ui/refractive-cursor-lens";

export default function Hero() {
  return (
    <RefractiveCursorLens
      size={200}
      displacementScale={36}
      springConfig={{ stiffness: 90, damping: 18 }}
      className="min-h-[60vh] flex items-center justify-center"
    >
      <h1 className="text-7xl font-bold tracking-tight">
        Trail your cursor.
      </h1>
    </RefractiveCursorLens>
  );
}
